import{c as h,S as i,j as t,m as a}from"./chunks/framework.8aa1YH_s.js";const k=JSON.parse('{"title":"Quản lý Học viên","description":"","frontmatter":{},"headers":[],"relativePath":"admin/quan-ly-hoc-vien.md","filePath":"admin/quan-ly-hoc-vien.md","lastUpdated":0}'),o={name:"admin/quan-ly-hoc-vien.md"};function c(l,n,g,r,s,e){return i(),t("div",null,[...n[0]||(n[0]=[a('<h1 id="quan-ly-hoc-vien" tabindex="-1">Quản lý Học viên <a class="header-anchor" href="#quan-ly-hoc-vien" aria-label="Permalink to “Quản lý Học viên”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/account/student</code></p><p>Đây là nơi quản lý toàn bộ tài khoản học viên: xem danh sách, tạo / sửa / khóa / xóa tài khoản, xem chi tiết tiến độ học của từng người.</p><h2 id="danh-sach-hoc-vien" tabindex="-1">Danh sách học viên <a class="header-anchor" href="#danh-sach-hoc-vien" aria-label="Permalink to “Danh sách học viên”">​</a></h2><p>Bảng hiển thị các cột:</p><ul><li><strong>Họ và tên</strong></li><li><strong>Số điện thoại / Email</strong></li><li><strong>Ngày sinh, Giới tính</strong></li><li><strong>Tỉnh / Thành phố</strong></li><li><strong>Khối lớp</strong> (10/11/12)</li><li><strong>Ngày đăng ký</strong></li><li><strong>Số khóa đã mua</strong></li><li><strong>Trạng thái</strong> (Hoạt động / Tạm khóa)</li><li><strong>Thao tác</strong> (Xem / Sửa / Khóa / Xóa)</li></ul><h2 id="tim-kiem-loc" tabindex="-1">Tìm kiếm &amp; Lọc <a class="header-anchor" href="#tim-kiem-loc" aria-label="Permalink to “Tìm kiếm &amp; Lọc”">​</a></h2><ul><li>Ô tìm kiếm theo <strong>họ tên, số điện thoại, email</strong>.</li><li>Bộ lọc theo <strong>trạng thái</strong>, <strong>khoảng ngày đăng ký</strong>, <strong>khối lớp</strong>, <strong>tỉnh/thành</strong>, <strong>khóa học đã mua</strong>.</li></ul><h2 id="them-hoc-vien-thu-cong" tabindex="-1">Thêm học viên (thủ công) <a class="header-anchor" href="#them-hoc-vien-thu-cong" aria-label="Permalink to “Thêm học viên (thủ công)”">​</a></h2><p>Thông thường học viên tự đăng ký. Khi cần tạo thủ công (vd: học viên offline chuyển lên):</p><ol><li>Bấm <strong>Thêm học viên</strong>.</li><li>Điền: Họ tên, Số điện thoại, Email, Mật khẩu mặc định, Ngày sinh, Giới tính, Tỉnh / Thành, Khối lớp.</li><li>(Tùy chọn) Chọn ngay <strong>Khóa học cần gán</strong> cho học viên.</li><li>Bấm <strong>Lưu</strong>. Hệ thống gửi SMS/email tài khoản cho học viên.</li></ol><h2 id="sua-thong-tin-hoc-vien" tabindex="-1">Sửa thông tin học viên <a class="header-anchor" href="#sua-thong-tin-hoc-vien" aria-label="Permalink to “Sửa thông tin học viên”">​</a></h2><ul><li>Bấm icon <strong>Sửa</strong> trên dòng tương ứng.</li><li>Chỉnh các trường cần đổi → bấm <strong>Lưu</strong>.</li><li>Trường <strong>Số điện thoại</strong> và <strong>Email</strong> là duy nhất, nếu trùng với người khác sẽ báo lỗi.</li></ul><h2 id="xem-chi-tiet-mot-hoc-vien" tabindex="-1">Xem chi tiết một học viên <a class="header-anchor" href="#xem-chi-tiet-mot-hoc-vien" aria-label="Permalink to “Xem chi tiết một học viên”">​</a></h2><p><code>https://lamsonedutech.vn/admin/account/student/:id</code></p><p>Trang chi tiết cho phép xem:</p><ul><li>Thông tin cá nhân.</li><li><strong>Danh sách khóa học đã mua</strong> (kèm ngày mua, giá, mã đơn).</li><li><strong>Lịch sử làm bài thi</strong>: tên đề, ngày làm, điểm, thời gian, link xem lại.</li><li><strong>Tiến độ học</strong>: % bài giảng đã xem, chuyên đề đã hoàn thành.</li><li><strong>Hóa đơn</strong>: các đơn đã thanh toán.</li></ul><p>Bấm vào một bài thi để mở <a href="/hoc-vien/xem-lai-bai-thi">Lịch sử làm bài</a> - rất hữu ích khi học viên khiếu nại &quot;tôi không làm bài này&quot;.</p><h2 id="khoa-mo-khoa-tai-khoan" tabindex="-1">Khóa / Mở khóa tài khoản <a class="header-anchor" href="#khoa-mo-khoa-tai-khoan" aria-label="Permalink to “Khóa / Mở khóa tài khoản”">​</a></h2><ul><li>Khi học viên vi phạm (gian lận thi cử, lạm dụng tài khoản): bấm icon <strong>Khóa</strong>.</li><li>Học viên bị khóa <strong>không đăng nhập được</strong> và <strong>không thể làm bài thi</strong>.</li><li>Bấm lại để <strong>Mở khóa</strong>.</li></ul><blockquote><p>💡 Nên ghi chú lý do khóa vào trường ghi chú để các admin khác biết.</p></blockquote><h2 id="xoa-tai-khoan" tabindex="-1">Xóa tài khoản <a class="header-anchor" href="#xoa-tai-khoan" aria-label="Permalink to “Xóa tài khoản”">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Lưu ý</p><p>Xóa tài khoản sẽ làm mất <strong>toàn bộ lịch sử học và hóa đơn</strong> của học viên. Chỉ xóa khi chắc chắn (tài khoản test, đăng ký nhầm, học viên yêu cầu xóa theo GDPR).</p><p>Thay vì xóa, <strong>hãy ưu tiên Khóa</strong> tài khoản.</p></div><ol><li>Bấm icon <strong>Xóa</strong> trên dòng.</li><li>Xác nhận trong popup.</li><li>Tài khoản và mọi dữ liệu liên quan sẽ bị xóa vĩnh viễn.</li></ol><h2 id="gan-khoa-hoc-mien-phi-cho-hoc-vien" tabindex="-1">Gán khóa học miễn phí cho học viên <a class="header-anchor" href="#gan-khoa-hoc-mien-phi-cho-hoc-vien" aria-label="Permalink to “Gán khóa học miễn phí cho học viên”">​</a></h2><p>Trường hợp khuyến mại VIP, học sinh học bổng, hoặc bù lỗi:</p><ol><li>Vào chi tiết học viên.</li><li>Tab <strong>Khóa học</strong> → bấm <strong>Thêm khóa học</strong>.</li><li>Chọn khóa cần gán → chọn <strong>Miễn phí</strong> hoặc nhập giá tùy chỉnh.</li><li>Bấm <strong>Gán</strong>. Học viên có thể vào học ngay.</li></ol><p>Cách khác là dùng <a href="./hoc-vien-khoa-hoc">Học viên - Khóa học</a> để gán hàng loạt.</p><h2 id="xuat-danh-sach" tabindex="-1">Xuất danh sách <a class="header-anchor" href="#xuat-danh-sach" aria-label="Permalink to “Xuất danh sách”">​</a></h2><ul><li>Bấm <strong>Xuất Excel</strong> để tải toàn bộ danh sách đã lọc.</li><li>Có thể dùng file này để gửi SMS/email marketing.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên nói &quot;không nhận được mật khẩu khi đăng ký&quot;.</strong> → Vào chi tiết → bấm <strong>Reset mật khẩu</strong>, hệ thống gửi lại mật khẩu mới.</p><p><strong>Học viên muốn đổi số điện thoại.</strong> → Sửa số trong thông tin tài khoản. Nếu yêu cầu xác thực OTP, hãy giải thích cho học viên thực hiện qua mục <strong>Hồ sơ cá nhân</strong> trên app của họ.</p><p><strong>Một số điện thoại đã được dùng để đăng ký nhưng học viên nói chưa từng đăng ký.</strong> → Tìm số đó trong danh sách. Nếu là tài khoản chưa kích hoạt và chưa mua khóa, có thể xóa để học viên đăng ký lại.</p>',34)])])}const u=h(o,[["render",c]]);export{k as __pageData,u as default};
